#include <iostream>
#include <string>
#include <string_view>

class Employee
{
    std::string m_name;
    int m_age{};
public:
    Employee(std::string_view name, int age)
        : m_name{ name }, m_age{ age }
    {
        std::cout << "Employee constructed: " << m_name << " age " << m_age << '\n';
    }
    ~Employee() { std::cout << "Employee destroyed\n"; }
    std::string describe() const
    {
        return std::string{m_name} + " (age " + std::to_string(m_age) + ")";
    }
};

class Manager : public Employee
{
    std::string m_role;
    int m_teamSize{};
public:
    Manager(std::string_view name, int age, std::string_view role, int teamSize)
        : Employee{ name, age }, m_role{ role }, m_teamSize{ teamSize }
    {
        std::cout << "Manager constructed: " << m_role << " team " << m_teamSize << '\n';
    }
    ~Manager() { std::cout << "Manager destroyed\n"; }
    std::string describe() const
    {
        return Employee::describe() + ", " + std::string{m_role}
            + ", manages " + std::to_string(m_teamSize);
    }
};

int main()
{
    std::string name{};
    int age{};
    std::string role{};
    std::cin >> name >> age >> role;
    int teamSize{};
    std::cin >> teamSize;
    {
        Manager mgr{ name, age, role, teamSize };
        std::cout << '\n' << mgr.describe() << "\n\n";
    }
    return 0;
}

