#include <algorithm>
#include <iostream>
#include <string>
#include <string_view>

class Vehicle
{
protected:
    std::string m_model;
    int m_topSpeed{};
    int m_currentSpeed{};
public:
    Vehicle(std::string_view model, int topSpeed, int currentSpeed)
        : m_model{ model }, m_topSpeed{ topSpeed }, m_currentSpeed{ currentSpeed } {}
    void status() const
    {
        std::cout << m_model << ": " << m_currentSpeed << '/' << m_topSpeed << " km/h\n";
    }
    void setSpeed(int speed) { m_currentSpeed = speed; }
};

class RaceCar : public Vehicle
{
public:
    RaceCar(std::string_view model, int topSpeed, int currentSpeed)
        : Vehicle{ model, topSpeed, currentSpeed } {}
    void boost() { m_currentSpeed = std::min(m_currentSpeed + 30, m_topSpeed); }
    int getSpeed() const { return m_currentSpeed; }
    void setSpeed(int) { std::cout << "setSpeed is disabled for RaceCar\n"; }
};

int main()
{
    std::string model{};
    int topSpeed{};
    int currentSpeed{};
    std::cin >> model >> topSpeed >> currentSpeed;
    int boostCount{};
    std::cin >> boostCount;

    RaceCar car{ model, topSpeed, currentSpeed };
    car.status();
    for (int i{ 1 }; i <= boostCount; ++i)
    {
        car.boost();
        std::cout << "Boost " << i << ": " << car.getSpeed() << " km/h\n";
    }
    car.status();
    car.setSpeed(0);
    return 0;
}
